/// Vertex format for 2D rendering
#[derive(Debug, Clone, Copy, PartialEq)]
pub struct VertexFormat {
    pub position: bool,
    pub color: bool,
    pub tex_coords: bool,
}

impl VertexFormat {
    pub fn basic_2d() -> Self {
        Self { position: true, color: true, tex_coords: false }
    }

    pub fn textured_2d() -> Self {
        Self { position: true, color: true, tex_coords: true }
    }

    pub fn size_in_floats(&self) -> u64 {
        let mut size = 0;
        if self.position { size += 2; }
        if self.color { size += 4; }
        if self.tex_coords { size += 2; }
        size
    }
}
